const body = $input.first().json;
const data = body.data || body;
const key = data.key || {};
const message = data.message || {};

const messageId = key.id || '';
const remoteJidRaw = key.remoteJid || '';
const remoteJid = remoteJidRaw.replace('@s.whatsapp.net','').replace('@g.us','');
const fromMe = key.fromMe || false;
const messageType = data.messageType || 'unknown';
const pushName = data.pushName || data.verifiedBizName || '';

if (fromMe) return [];

let userText = '';
let isValidFormat = true;

switch (messageType) {
  case 'conversation':               userText = message.conversation || ''; break;
  case 'extendedTextMessage':        userText = message.extendedTextMessage?.text || ''; break;
  case 'listResponseMessage':        userText = message.listResponseMessage?.singleSelectReply?.selectedRowId || ''; break;
  case 'buttonsResponseMessage':     userText = message.buttonsResponseMessage?.selectedButtonId || ''; break;
  case 'templateButtonReplyMessage': userText = message.templateButtonReplyMessage?.selectedId || ''; break;
  default: isValidFormat = false;
}

function sanitize(text) {
  if (!text) return '';
  let s = text.slice(0,1000).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g,'');
  if (/\bignore (previous|above|all)\b|\bforget (everything|all)\b|\bsystem prompt\b/i.test(s)) s = '[mensaje filtrado]';
  return s.trim();
}

return [{ json: { message_id:messageId, remote_jid:remoteJid, whatsapp_name:pushName, message_type:messageType, user_text:sanitize(userText), is_valid_format:isValidFormat, timestamp_ms:Date.now() } }];

const data = $input.first().json;
const jid = data.remote_jid;
const msgId = data.message_id;

const REDIS_URL = $env.REDIS_REST_URL;
const REDIS_TOKEN = $env.REDIS_REST_TOKEN;

async function rGet(key) {
  try {
    const r = await fetch(`${REDIS_URL}/get/${encodeURIComponent(key)}`, { headers: { Authorization: `Bearer ${REDIS_TOKEN}` } });
    return (await r.json()).result;
  } catch(e) { return null; }
}
async function rIncr(key) {
  try {
    const r = await fetch(`${REDIS_URL}/incr/${encodeURIComponent(key)}`, { method:'POST', headers: { Authorization: `Bearer ${REDIS_TOKEN}` } });
    return (await r.json()).result;
  } catch(e) { return 1; }
}
function rExpireAsync(key, ttl) {
  fetch(`${REDIS_URL}/expire/${encodeURIComponent(key)}/${ttl}`, { method:'POST', headers: { Authorization: `Bearer ${REDIS_TOKEN}` } }).catch(()=>{});
}

const [dedupCount, sessionRaw, lockRaw, maintenanceRaw, configRaw, configVersionRaw, cbEvolution, cbSheets] = await Promise.all([
  rIncr(`dedup:${msgId}`),
  rGet(`session:${jid}`),
  rGet(`lock:${jid}`),
  rGet('maintenance_mode'),
  rGet('config:qa'),
  rGet('config:qa:version'),
  rGet('cb:evolution:count'),
  rGet('cb:sheets:count')
]);

rExpireAsync(`dedup:${msgId}`, 60);

const dedup = parseInt(dedupCount) || 1;
let session = {}; try { session = JSON.parse(sessionRaw || '{}'); } catch(e) {}
let lock    = {}; try { lock    = JSON.parse(lockRaw    || '{}'); } catch(e) {}
let qaRows  = null; try { qaRows = configRaw ? JSON.parse(configRaw) : null; } catch(e) {}

const CB_THRESHOLD = parseInt($env.CB_THRESHOLD) || 5;

return [{ json: {
  message_id: msgId, remote_jid: jid, whatsapp_name: data.whatsapp_name,
  message_type: data.message_type, user_text: data.user_text, timestamp_ms: data.timestamp_ms,
  is_duplicate:    dedup > 1,
  is_locked:       lock.is_processing === true,
  is_maintenance:  maintenanceRaw === '1',
  is_human_active: session.is_human_active === true,
  is_new_user:     !session.step_id,
  session:         session,
  qa_rows_cached:  qaRows,
  config_version:         parseInt(configVersionRaw) || 0,
  session_config_version: parseInt(session.config_version) || 0,
  cb_evolution_open: parseInt(cbEvolution) >= CB_THRESHOLD,
  cb_sheets_open:    parseInt(cbSheets)    >= CB_THRESHOLD
}}];

const d = $input.first().json;
if (d.is_duplicate)    return [];
if (d.is_locked)       return [];
if (d.is_human_active) return [];
if (d.is_maintenance)  return [{ json: { ...d, _action: 'maintenance' } }];
const configChanged = d.config_version > 0 && d.session_config_version > 0 && d.config_version !== d.session_config_version;
if (configChanged)     return [{ json: { ...d, _action: 'config_reset' } }];
return [{ json: { ...d, _action: 'process' } }];

const d = $input.first().json;
const texts = {
  maintenance:  '⚙️ Estamos realizando tareas de mantenimiento. Por favor volvé en unos minutos.',
  config_reset: 'Actualizamos nuestro sistema de información. ¿Podés contarnos nuevamente en qué podemos ayudarte?'
};
return [{ json: { ...d, _special_text: texts[d._action] || '' } }];

const d = $('Code — Validar en Memoria').first().json;
if (d._action !== 'config_reset') return [];
return [{ json: { remote_jid: d.remote_jid, new_session: JSON.stringify({ step_id:'INICIO', is_human_active:false, config_version:d.config_version, last_message_id:d.message_id, timestamp_ms:Date.now() }) } }];

const items = $input.all();
const hasError = items.some(i => i.json.error);
const REDIS_URL = $env.REDIS_REST_URL;
const REDIS_TOKEN = $env.REDIS_REST_TOKEN;

if (hasError) {
  await fetch(`${REDIS_URL}/incr/cb:sheets:count`, { method:'POST', headers:{ Authorization:`Bearer ${REDIS_TOKEN}` } });
  await fetch(`${REDIS_URL}/expire/cb:sheets:count/${$env.CB_WINDOW_TTL||60}`, { method:'POST', headers:{ Authorization:`Bearer ${REDIS_TOKEN}` } });
  return [{ json: { rows:[{ step_id:'INICIO', mensaje_bot:'Estamos procesando su consulta. Un asesor lo contactará a la brevedad.', tipo_input:'text', step_siguiente_default:'FIN' }], source:'sheets_error_fallback' } }];
}

fetch(`${REDIS_URL}/del/cb:sheets:count`, { method:'POST', headers:{ Authorization:`Bearer ${REDIS_TOKEN}` } }).catch(()=>{});
const rowsData = items.map(i => i.json);
const newVersion = Date.now();
await fetch(`${REDIS_URL}/set/config:qa:version/${newVersion}`, { method:'POST', headers:{ Authorization:`Bearer ${REDIS_TOKEN}` } });
return [{ json: { rows:rowsData, source:'sheets', _new_version:newVersion, _cache_value:JSON.stringify(rowsData) } }];

const batchData = $('Code — Redis Batch (paralelo)').first().json;

let qaRows;
const cachedRows = batchData.qa_rows_cached;
if (cachedRows && Array.isArray(cachedRows) && cachedRows.length > 0) {
  qaRows = cachedRows;
} else {
  try { qaRows = $('Google Sheets — Q&A').all().map(i => i.json); } catch(e) { qaRows = []; }
}

const session = batchData.session || {};
const currentStepId = session.step_id || 'INICIO';
const userText = batchData.user_text || '';
const jid = batchData.remote_jid;

const currentStep = qaRows.find(r => r.step_id === currentStepId);

if (!currentStep && currentStepId !== 'INICIO') {
  const inicioStep = qaRows.find(r => r.step_id === 'INICIO');
  return [{ json: { ...batchData, current_step_id:'INICIO', next_step_id:'INICIO', bot_message:inicioStep?.mensaje_bot||'Hola, ¿en qué podemos ayudarte?', message_type_out:'text', options:[], new_session:JSON.stringify({ step_id:'INICIO', is_human_active:false, config_version:batchData.config_version, last_message_id:batchData.message_id, timestamp_ms:Date.now() }), _evolution_body:{ number:jid, text:inicioStep?.mensaje_bot||'Hola, ¿en qué podemos ayudarte?' }, _evolution_endpoint:'sendText' }}];
}

let nextStepId = currentStep?.step_siguiente_default || 'FIN';
if (currentStep?.step_por_opcion) { try { const m = JSON.parse(currentStep.step_por_opcion); if (m[userText]) nextStepId = m[userText]; } catch(e) {} }

const nextStep = qaRows.find(r => r.step_id === nextStepId);
const botMessage = nextStep?.mensaje_bot || 'Gracias por tu consulta. Un asesor te contactará a la brevedad.';
const messageTypeOut = nextStep?.tipo_input || 'text';
const parsedOptions = (nextStep?.opciones||'').split(',').map(o=>o.trim()).filter(Boolean);
const newSession = JSON.stringify({ step_id:nextStepId, is_human_active:session.is_human_active||false, config_version:batchData.config_version, last_message_id:batchData.message_id, timestamp_ms:Date.now() });

let evolutionEndpoint = 'sendText';
let evolutionBody = {};
if (messageTypeOut === 'list' && parsedOptions.length > 0) {
  evolutionEndpoint = 'sendList';
  evolutionBody = { number:jid, title:botMessage, description:'Seleccioná una opción', buttonText:'Ver opciones', footerText:'', sections:[{ title:'Opciones disponibles', rows:parsedOptions.map(opt=>({ title:opt, rowId:opt.toLowerCase().replace(/\s+/g,'_'), description:'' })) }] };
} else if (messageTypeOut === 'button' && parsedOptions.length > 0) {
  evolutionEndpoint = 'sendButtons';
  evolutionBody = { number:jid, title:botMessage, description:'', footer:'', buttons:parsedOptions.slice(0,3).map(opt=>({ type:'reply', displayText:opt, id:opt.toLowerCase().replace(/\s+/g,'_') })) };
} else {
  evolutionBody = { number:jid, text:botMessage };
}

return [{ json: { message_id:batchData.message_id, remote_jid:jid, whatsapp_name:batchData.whatsapp_name, user_text:batchData.user_text, is_new_user:batchData.is_new_user, current_step_id:currentStepId, next_step_id:nextStepId, bot_message:botMessage, message_type_out:messageTypeOut, options:parsedOptions, new_session:newSession, _evolution_endpoint:evolutionEndpoint, _evolution_body:evolutionBody } }];

const result = $input.first().json;
const hasError = result.error || (result.statusCode && result.statusCode >= 500);
const REDIS_URL = $env.REDIS_REST_URL;
const REDIS_TOKEN = $env.REDIS_REST_TOKEN;

if (hasError) {
  await fetch(`${REDIS_URL}/incr/cb:evolution:count`, { method:'POST', headers:{ Authorization:`Bearer ${REDIS_TOKEN}` } });
  await fetch(`${REDIS_URL}/expire/cb:evolution:count/${$env.CB_WINDOW_TTL||60}`, { method:'POST', headers:{ Authorization:`Bearer ${REDIS_TOKEN}` } });
  throw new Error(`EvolutionAPI Send falló: ${result.error || result.statusCode}`);
}

fetch(`${REDIS_URL}/del/cb:evolution:count`, { method:'POST', headers:{ Authorization:`Bearer ${REDIS_TOKEN}` } }).catch(()=>{});
return $input.all();

const items = $input.all();
const now = new Date();
const ar = new Date(now.toLocaleString('en-US',{timeZone:'America/Argentina/Buenos_Aires'}));
if (ar.getHours() < 8 || ar.getHours() >= 20) return [];
return items.map(i => ({ json: i.json }));
